import{_ as s,c as a,o as e,V as n}from"./chunks/framework.1sOznGPE.js";const u=JSON.parse('{"title":"v-if与v-show的区别以及使用场景","description":"","frontmatter":{},"headers":[],"relativePath":"guide/interview/vue/指令/v-if与v-show的区别以及使用场景.md","filePath":"guide/interview/vue/指令/v-if与v-show的区别以及使用场景.md","lastUpdated":1719242077000}'),i={name:"guide/interview/vue/指令/v-if与v-show的区别以及使用场景.md"},o=n(`<h1 id="v-if与v-show的区别以及使用场景" tabindex="-1">v-if与v-show的区别以及使用场景 <a class="header-anchor" href="#v-if与v-show的区别以及使用场景" aria-label="Permalink to &quot;v-if与v-show的区别以及使用场景&quot;">​</a></h1><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>1. 手段：v-if是通过控制dom节点的存在与否来控制元素的显隐；v-show是通过设置DOM元素的display样式，block为显示，none为隐藏；</span></span>
<span class="line"><span>2. 编译过程：v-if切换有一个局部编译/卸载的过程，切换过程中合适地销毁和重建内部的事件监听和子组件；v-show只是简单的基于css切换；</span></span>
<span class="line"><span>3. 编译条件：v-if是惰性的，如果初始条件为假，则什么也不做；只有在条件第一次变为真时才开始局部编译; v-show是在任何条件下（首次条件是否为真）都被编译，然后被缓存，而且DOM元素保留；</span></span>
<span class="line"><span>4. 性能消耗：v-if有更高的切换消耗；v-show有更高的初始渲染消耗；</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>使用场景</strong></p><p>基于以上区别，因此，如果需要非常频繁地切换，则使用 v-show 较好；如果在运行时条件很少改变，则使用 v-if 较好。</p><ul><li><p>v-if 是真正的条件渲染，因为它会确保在切换过程中条件块内的事件监听器和子组件适当地被销毁和重建，而v-show 元素总是会被渲染，只是简单地基于css进行切换</p></li><li><p>频繁的去控制元素的显示和隐藏 就 使用 v-show，反之运行条件很少改变就使用 v-if</p></li></ul>`,5),p=[o];function t(l,v,r,c,_,d){return e(),a("div",null,p)}const f=s(i,[["render",t]]);export{u as __pageData,f as default};
